import csv
import io

def calculate_averages(csv_text, numeric_cols):
    """Calculate the average for each specified numeric column.
    Return a dict mapping column name to average (rounded to 2 decimals)."""
    reader = csv.DictReader(io.StringIO(csv_text))
    totals = {col: 0.0 for col in numeric_cols}
    count = 0
    for row in reader:
        count += 1
        for col in numeric_cols:
            totals[col] += float(row[col])
    if count == 0:
        return {col: 0.0 for col in numeric_cols}
    return {col: round(totals[col] / count, 2) for col in numeric_cols}

def find_max_row(csv_text, column):
    """Find and return the row (as a dict) with the maximum value in the specified column."""
    reader = csv.DictReader(io.StringIO(csv_text))
    rows = list(reader)
    if not rows:
        return None
    return max(rows, key=lambda r: float(r[column]))

def sort_csv(csv_text, column):
    """Sort CSV rows by the specified column (ascending, numeric-aware).
    Return the sorted CSV text."""
    reader = csv.DictReader(io.StringIO(csv_text))
    headers = reader.fieldnames
    rows = list(reader)
    try:
        rows.sort(key=lambda r: float(r[column]))
    except ValueError:
        rows.sort(key=lambda r: r[column])
    output = io.StringIO()
    writer = csv.DictWriter(output, fieldnames=headers)
    writer.writeheader()
    writer.writerows(rows)
    return output.getvalue().strip()

def csv_stats(csv_text, column):
    """Return a dict with 'min', 'max', 'mean', 'count' for the specified numeric column.
    All values rounded to 2 decimals where applicable."""
    reader = csv.DictReader(io.StringIO(csv_text))
    values = [float(row[column]) for row in reader]
    if not values:
        return {'min': 0, 'max': 0, 'mean': 0, 'count': 0}
    return {
        'min': round(min(values), 2),
        'max': round(max(values), 2),
        'mean': round(sum(values) / len(values), 2),
        'count': len(values)
    }
